def fibonacci(n):
    if n <= 0:
        return []
    elif n == 1:
        return [0]

    fib = [0, 1]
    for i in range(2, n):
        fib.append(fib[i-1] + fib[i-2])
    return fib

const debounce = (func, wait, immediate = false) => {
  let timeout;
  return function executedFunction(...args) {
    const context = this;
    const later = () => {
      timeout = null;
      if (!immediate) func.apply(context, args);
    };
    const callNow = immediate && !timeout;
    clearTimeout(timeout);
    timeout = setTimeout(later, wait);
    if (callNow) func.apply(context, args);
  };
};

function formatDate(d) {
  var m = d.getMonth() + 1;
  var day = d.getDate();
  var y = d.getFullYear();
  return y + '-' + (m < 10 ? '0' : '') + m + '-' + (day < 10 ? '0' : '') + day;
}

interface CacheOptions<T> {
  maxSize: number;
  ttl: number;
  onEvict?: (key: string, value: T) => void;
}

class LRUCache<T> {
  private cache = new Map<string, { value: T; expiry: number }>();
  private options: CacheOptions<T>;

  constructor(options: CacheOptions<T>) {
    this.options = options;
  }

  get(key: string): T | undefined {
    const entry = this.cache.get(key);
    if (!entry) return undefined;
    if (Date.now() > entry.expiry) {
      this.cache.delete(key);
      return undefined;
    }
    // Move to end (most recently used)
    this.cache.delete(key);
    this.cache.set(key, entry);
    return entry.value;
  }

  set(key: string, value: T): void {
    if (this.cache.has(key)) {
      this.cache.delete(key);
    } else if (this.cache.size >= this.options.maxSize) {
      const firstKey = this.cache.keys().next().value!;
      const evicted = this.cache.get(firstKey)!;
      this.cache.delete(firstKey);
      this.options.onEvict?.(firstKey, evicted.value);
    }
    this.cache.set(key, { value, expiry: Date.now() + this.options.ttl });
  }
}

const deepClone = (obj) => {
  if (obj === null || typeof obj !== 'object') return obj;
  if (obj instanceof Date) return new Date(obj.getTime());
  if (obj instanceof RegExp) return new RegExp(obj.source, obj.flags);
  if (Array.isArray(obj)) return obj.map(item => deepClone(item));

  const cloned = Object.create(Object.getPrototypeOf(obj));
  for (const key of Reflect.ownKeys(obj)) {
    const descriptor = Object.getOwnPropertyDescriptor(obj, key);
    if (descriptor) {
      if ('value' in descriptor) {
        descriptor.value = deepClone(descriptor.value);
      }
      Object.defineProperty(cloned, key, descriptor);
    }
  }
  return cloned;
};

